					nonNameCurrencyPart = options.currency;
					break;
				case "symbol":
					nonNameCurrencyPart = byCurrencyDisplay.symbol;
					break;
				default:
					nonNameCurrencyPart = byCurrencyDisplay.narrow;
					break;
			}
		} else {
			// Fallback for unknown currency
			nonNameCurrencyPart = options.currency;
		}
